import { IEmployeeRepository } from './employee.repository';
import { Employee } from './employee.model';

export interface IEmployeeService {
  getEmployeeById(id: string): Promise<Employee | null>;
  getEmployeeByEmail(email: string): Promise<Employee | null>;
  employeeExists(id: string): Promise<boolean>;
  getManagerHierarchy(employeeId: string): Promise<Employee[]>;
  isManagerOf(managerId: string, employeeId: string): Promise<boolean>;
}

export class EmployeeService implements IEmployeeService {
  constructor(private readonly employeeRepository: IEmployeeRepository) {}

  async getEmployeeById(id: string): Promise<Employee | null> {
    if (!id || typeof id !== 'string') {
      throw new Error('Invalid employee ID');
    }
    try {
      return await this.employeeRepository.findById(id);
    } catch (error) {
      console.error('Error fetching employee by ID');
      throw error;
    }
  }

  async getEmployeeByEmail(email: string): Promise<Employee | null> {
    if (!email || typeof email !== 'string' || !email.includes('@')) {
      throw new Error('Invalid email');
    }
    try {
      return await this.employeeRepository.findByEmail(email);
    } catch (error) {
      console.error('Error fetching employee by email');
      throw error;
    }
  }

  async employeeExists(id: string): Promise<boolean> {
    if (!id || typeof id !== 'string') {
      throw new Error('Invalid employee ID');
    }
    try {
      return await this.employeeRepository.exists(id);
    } catch (error) {
      console.error('Error checking employee existence');
      throw error;
    }
  }

  async getManagerHierarchy(employeeId: string): Promise<Employee[]> {
    if (!employeeId || typeof employeeId !== 'string') {
      throw new Error('Invalid employee ID');
    }
    try {
      return await this.employeeRepository.getManagerHierarchy(employeeId);
    } catch (error) {
      console.error('Error fetching manager hierarchy');
      throw error;
    }
  }

  async isManagerOf(managerId: string, employeeId: string): Promise<boolean> {
    if (!managerId || typeof managerId !== 'string' || !employeeId || typeof employeeId !== 'string') {
      throw new Error('Invalid manager or employee ID');
    }
    try {
      return await this.employeeRepository.isManagerOf(managerId, employeeId);
    } catch (error) {
      console.error('Error checking manager relationship');
      throw error;
    }
  }
