import { EmployeeService, IEmployeeService } from '../../../src/modules/employee/employee.service';
import { IEmployeeRepository } from '../../../src/modules/employee/employee.repository';
import { Employee } from '../../../src/modules/employee/employee.model';

describe('EmployeeService', () => {
  let service: IEmployeeService;
  let mockRepository: jest.Mocked<IEmployeeRepository>;

  beforeEach(() => {
    mockRepository = {
      findById: jest.fn(),
      findByEmail: jest.fn(),
      exists: jest.fn(),
      getManagerHierarchy: jest.fn(),
      isManagerOf: jest.fn(),
    };
    service = new EmployeeService(mockRepository);
  });

  describe('getEmployeeById', () => {
    it('should return employee when found', async () => {
      const employee: Employee = { id: '1', name: 'John', email: 'john@example.com', managerId: null, department: 'Engineering', status: 'active', createdAt: new Date(), updatedAt: new Date() };
      mockRepository.findById.mockResolvedValue(employee);
      const result = await service.getEmployeeById('1');
      expect(result).toEqual(employee);
      expect(mockRepository.findById).toHaveBeenCalledWith('1');
    });

    it('should return null when not found', async () => {
      mockRepository.findById.mockResolvedValue(null);
      const result = await service.getEmployeeById('nonexistent');
      expect(result).toBeNull();
    });

    it('should throw error for invalid id', async () => {
      await expect(service.getEmployeeById('')).rejects.toThrow('Invalid employee ID');
      await expect(service.getEmployeeById(null as any)).rejects.toThrow('Invalid employee ID');
    });

    it('should propagate repository errors', async () => {
      mockRepository.findById.mockRejectedValue(new Error('DB error'));
      await expect(service.getEmployeeById('1')).rejects.toThrow('DB error');
    });
  });

  describe('getEmployeeByEmail', () => {
    it('should return employee when found', async () => {
      const employee: Employee = { id: '1', name: 'John', email: 'john@example.com', managerId: null, department: 'Engineering', status: 'active', createdAt: new Date(), updatedAt: new Date() };
      mockRepository.findByEmail.mockResolvedValue(employee);
      const result = await service.getEmployeeByEmail('john@example.com');
      expect(result).toEqual(employee);
      expect(mockRepository.findByEmail).toHaveBeenCalledWith('john@example.com');
    });

    it('should return null when not found', async () => {
      mockRepository.findByEmail.mockResolvedValue(null);
      const result = await service.getEmployeeByEmail('unknown@example.com');
      expect(result).toBeNull();
    });

    it('should throw error for invalid email', async () => {
      await expect(service.getEmployeeByEmail('')).rejects.toThrow('Invalid email');
      await expect(service.getEmployeeByEmail('invalid')).rejects.toThrow('Invalid email');
    });

    it('should propagate repository errors', async () => {
      mockRepository.findByEmail.mockRejectedValue(new Error('DB error'));
      await expect(service.getEmployeeByEmail('john@example.com')).rejects.toThrow('DB error');
    });
  });

  describe('employeeExists', () => {
    it('should return true when employee exists', async () => {
      mockRepository.exists.mockResolvedValue(true);
      const result = await service.employeeExists('1');
      expect(result).toBe(true);
      expect(mockRepository.exists).toHaveBeenCalledWith('1');
    });

    it('should return false when employee does not exist', async () => {
      mockRepository.exists.mockResolvedValue(false);
      const result = await service.employeeExists('nonexistent');
      expect(result).toBe(false);
    });

    it('should throw error for invalid id', async () => {
      await expect(service.employeeExists('')).rejects.toThrow('Invalid employee ID');
    });

    it('should propagate repository errors', async () => {
      mockRepository.exists.mockRejectedValue(new Error('DB error'));
      await expect(service.employeeExists('1')).rejects.toThrow('DB error');
    });
  });

  describe('getManagerHierarchy', () => {
    it('should return hierarchy array', async () => {
      const hierarchy: Employee[] = [
        { id: '2', name: 'Manager', email: 'manager@example.com', managerId: null, department: 'Engineering', status: 'active', createdAt: new Date(), updatedAt: new Date() },
        { id: '1', name: 'John', email: 'john@example.com', managerId: '2', department: 'Engineering', status: 'active', createdAt: new Date(), updatedAt: new Date() }
      ];
      mockRepository.getManagerHierarchy.mockResolvedValue(hierarchy);
      const result = await service.getManagerHierarchy('1');
      expect(result).toEqual(hierarchy);
      expect(mockRepository.getManagerHierarchy).toHaveBeenCalledWith('1');
    });

    it('should throw error for invalid id', async () => {
      await expect(service.getManagerHierarchy('')).rejects.toThrow('Invalid employee ID');
    });

    it('should propagate repository errors', async () => {
      mockRepository.getManagerHierarchy.mockRejectedValue(new Error('DB error'));
      await expect(service.getManagerHierarchy('1')).rejects.toThrow('DB error');
    });
  });

  describe('isManagerOf', () => {
    it('should return true when manager relationship exists', async () => {
      mockRepository.isManagerOf.mockResolvedValue(true);
      const result = await service.isManagerOf('2', '1');
      expect(result).toBe(true);
      expect(mockRepository.isManagerOf).toHaveBeenCalledWith('2', '1');
    });

    it('should return false when not manager', async () => {
      mockRepository.isManagerOf.mockResolvedValue(false);
      const result = await service.isManagerOf('3', '1');
      expect(result).toBe(false);
    });

    it('should throw error for invalid ids', async () => {
      await expect(service.isManagerOf('', '1')).rejects.toThrow('Invalid manager or employee ID');
      await expect(service.isManagerOf('2', '')).rejects.toThrow('Invalid manager or employee ID');
    });

    it('should propagate repository errors', async () => {
      mockRepository.isManagerOf.mockRejectedValue(new Error('DB error'));
      await expect(service.isManagerOf('2', '1')).rejects.toThrow('DB error');
    });
  });
